import"./hoisted.BpWbGDA2.js";import"./hoisted.CmeptYci.js";document.addEventListener("DOMContentLoaded",()=>{if(window.matchMedia("(prefers-reduced-motion: reduce)").matches){document.querySelectorAll(".role-card").forEach(e=>e.classList.add("in-view"));return}const o=new IntersectionObserver(e=>{e.forEach(t=>{if(t.isIntersecting){const r=t.target,s=parseInt(r.dataset.i||"0",10);setTimeout(()=>r.classList.add("in-view"),s*120),o.unobserve(r)}})},{threshold:.2});document.querySelectorAll(".role-card").forEach((e,t)=>{e.dataset.i=String(t),o.observe(e)})});
